const e=JSON.parse(`[{"id":"listening_part1","title":"Listening Part 1: Short Conversations","levelRange":"B2","skill":"listening","moduleType":"listening_set","items":[{"id":"L01","script":"W: Are you going to the careers workshop this afternoon?\\nM: Not today. They moved it to next Thursday because the guest speaker missed her flight.\\nW: I'm glad you told me. I was about to leave for the hall.\\nN: What does the man say about the workshop?","questions":[{"stem":"What does the man say about the workshop?","options":["It has started late.","It will happen on another day.","It is only for new students.","It has changed rooms."],"correct":1,"explanation":"The man says they moved it to next Thursday — it will happen on a different day."}]},{"id":"L02","script":"W: Did you print the handouts for the meeting?\\nM: I tried, but the printer is out of paper, so I emailed everyone a copy instead.\\nW: Fine. That should work for today.\\nN: What problem did the man have?","questions":[{"stem":"What problem did the man have?","options":["He forgot the handouts at home.","The printer had no paper.","He sent the wrong file.","The meeting started early."],"correct":1,"explanation":"The man says the printer is out of paper."}]},{"id":"L03","script":"M: I can't believe your phone still works after all these years.\\nW: Barely. I'm keeping it until next month, when the newer model goes on sale.\\nN: What will the woman probably do next month?","questions":[{"stem":"What will the woman probably do next month?","options":["Repair her old phone.","Borrow a phone from a friend.","Change her phone plan.","Buy a new phone."],"correct":3,"explanation":"She is keeping her old phone until the newer model goes on sale — she will buy a new phone."}]},{"id":"L04","script":"W: Could you close the window? The traffic is really loud today.\\nM: I'd rather leave it open because it's warm in here, but if the noise is bothering you, I can shut it.\\nN: What does the man mean?","questions":[{"stem":"What does the man mean?","options":["He thinks the room is already too cold.","He wants the woman to move seats.","He prefers the window open but is willing to close it.","He cannot hear the traffic at all."],"correct":2,"explanation":"The man prefers it open but says he can shut it if the noise is bothering her."}]},{"id":"L11","script":"M: Are you free this Saturday to help me move my furniture?\\nW: I wish I could, but I'm driving my sister to the airport that morning.\\nM: What about Sunday?\\nW: Sunday should be fine. Just text me the address.\\nN: What will the woman do on Saturday?","questions":[{"stem":"What will the woman do on Saturday?","options":["Help the man move furniture.","Drive her sister to the airport.","Text the man the address.","Clean her own apartment."],"correct":1,"explanation":"She says she is driving her sister to the airport on Saturday."}]},{"id":"L12","script":"W: Did you check the bus schedule for tomorrow?\\nM: Yes, the first bus leaves at 6:15, but on weekends it starts at 7:30.\\nW: I forgot tomorrow is Sunday. So we have an extra hour to get ready.\\nN: What time does the first bus leave on weekdays?","questions":[{"stem":"What time does the first bus leave on weekdays?","options":["6:15","7:30","7:15","6:30"],"correct":0,"explanation":"The man says the first bus leaves at 6:15, but on weekends it starts at 7:30."}]},{"id":"L13","script":"W: I heard the library is going digital with most of its journals next month.\\nM: That is going to be a problem for some of the older faculty members who prefer print.\\nW: The library is offering a workshop to help them.\\nN: Why might some faculty members have difficulty?","questions":[{"stem":"Why might some faculty members have difficulty?","options":["The library is closing early.","They prefer printed journals.","The workshop is fully booked.","The library is charging new fees."],"correct":1,"explanation":"The man says older faculty members prefer print."}]},{"id":"L14","script":"M: I need to renew my passport before my conference in July.\\nW: Then you should apply soon. The processing time is about six weeks.\\nM: That is cutting it close. I will submit the application today.\\nN: What does the woman advise?","questions":[{"stem":"What does the woman advise?","options":["Cancel the conference.","Apply for the passport soon.","Use an express service.","Travel with the old passport."],"correct":1,"explanation":"She says he should apply soon because processing takes six weeks."}]}]},{"id":"listening_part2","title":"Listening Part 2: Longer Conversations","levelRange":"B2","skill":"listening","moduleType":"listening_set","items":[{"id":"L05","script":"N: Listen to a conversation between a student and an academic advisor.\\nAdvisor: So, you're thinking about taking Introduction to Marketing next term?\\nStudent: Yes, but the only section I can see is on Tuesday evenings, and that's when I usually work.\\nAdvisor: There is an online section, but it fills up quickly. If you want that one, you should register today.\\nStudent: I was hoping to take the in-person class because I learn better when I can ask questions right away.\\nAdvisor: That makes sense. Still, the online section might be the better choice if your work schedule can't change.\\nStudent: True. I'll call my manager this afternoon and see whether I can switch shifts. If not, I'll take the online class.","questions":[{"stem":"Why is the student worried about the course?","options":["He has already failed it once.","He may not be free at the class time.","He cannot find the classroom.","He thinks the teacher is too strict."],"correct":1,"explanation":"The student says the only section is on Tuesday evenings, when he usually works."},{"stem":"What will the student probably do first?","options":["Drop the course completely.","Register for a different subject.","Ask his manager about his work hours.","Join the online class immediately."],"correct":2,"explanation":"He says he will call his manager this afternoon to ask about switching shifts."}]},{"id":"L06","script":"N: Listen to a conversation in a bike rental shop.\\nAssistant: Are you renting for the city or for the trails?\\nCustomer: For the trails. My brother is visiting, and we planned a ride for Saturday.\\nAssistant: In that case, I should tell you that the hill trail is partly closed after last week's heavy rain.\\nCustomer: Oh. Is there another route you'd recommend?\\nAssistant: Yes. The river route is open, and it's easier too. I'd also suggest helmets and a repair kit.\\nCustomer: We definitely need helmets. Do they come with the bikes?\\nAssistant: They do, but the repair kit costs extra.\\nCustomer: That's fine. Let's do two bikes, two helmets, and one repair kit.","questions":[{"stem":"Why does the assistant mention the hill trail?","options":["To explain why the shop is busy.","To warn the customer about a route problem.","To suggest a more expensive bike.","To ask whether the customer is experienced."],"correct":1,"explanation":"The assistant warns that the hill trail is partly closed after heavy rain."},{"stem":"What will the customer probably rent?","options":["Two bikes and one helmet.","One bike and one repair kit.","Two bikes, helmets, and a repair kit.","Two bikes only."],"correct":2,"explanation":"The customer says 'Let's do two bikes, two helmets, and one repair kit.'"}]},{"id":"L07","script":"N: Listen to two roommates talking about an apartment.\\nW: I like the apartment on Green Street. It's cheaper than the others, and the kitchen is much nicer.\\nM: I liked that one too, but it's pretty far from the train station.\\nW: That's true, although the bus stop is right outside.\\nM: Did you notice how small the bedrooms were? I'm not sure my desk would fit.\\nW: Mine probably would, but just barely. On the other hand, internet is included in the rent, which would save us money every month.\\nM: Good point. Why don't we visit it again on Friday and measure the rooms?\\nW: That sounds like the best plan.","questions":[{"stem":"What does the woman see as an advantage of the apartment?","options":["It is close to the train station.","It has larger bedrooms.","It costs less and has a better kitchen.","It has new furniture included."],"correct":2,"explanation":"The woman says it is cheaper and the kitchen is much nicer."},{"stem":"What do the speakers decide to do?","options":["Sign the contract that day.","Visit the apartment again.","Look for a third roommate.","Cancel all future viewings."],"correct":1,"explanation":"The man suggests visiting again on Friday and the woman agrees."}]},{"id":"L15","script":"N: Listen to a conversation between a tenant and a landlord.\\nLandlord: So, you mentioned there is a problem with the heating?\\nTenant: Yes, the radiator in the bedroom has not been working for three days now.\\nLandlord: Did you check whether the valve is open? Sometimes that is all it is.\\nTenant: I did, but there is no heat coming through at all.\\nLandlord: All right. I will call a repair person tomorrow morning.\\nTenant: Is there any chance they could come today? It is really cold at night.\\nLandlord: I will ask if they can fit you in this evening, but I cannot promise anything.","questions":[{"stem":"What did the tenant already do before calling the landlord?","options":["Called another repair service.","Checked the valve on the radiator.","Bought a new heater.","Moved to a different room."],"correct":1,"explanation":"The tenant says he checked whether the valve is open."},{"stem":"What does the landlord promise?","options":["To send a repair person today.","To ask about an earlier appointment.","To reduce the rent.","To replace the radiator."],"correct":1,"explanation":"The landlord says she will ask if they can come this evening but cannot promise."}]},{"id":"L16","script":"N: Listen to a conversation at a pharmacy.\\nCustomer: Hello, I need to pick up a prescription for Dr. Miller.\\nPharmacist: Let me check. What is your date of birth?\\nCustomer: February 14, 1992.\\nPharmacist: Here it is. However, this medication needs to be taken with food, or it may upset your stomach.\\nCustomer: Good to know. Should I take it in the morning or at night?\\nPharmacist: The prescription says once daily, so whenever is most convenient for you, as long as you have eaten something recently.\\nCustomer: I will take it with breakfast then. How much do I owe you?\\nPharmacist: Your insurance covers most of it. That will be twelve dollars.","questions":[{"stem":"What important information does the pharmacist give?","options":["The medication is out of stock.","The prescription must be taken with food.","The price has increased.","The doctor needs to be called."],"correct":1,"explanation":"The pharmacist says the medication needs to be taken with food."},{"stem":"When does the customer decide to take the medication?","options":["At lunchtime.","Before bed.","With breakfast.","After dinner."],"correct":2,"explanation":"The customer decides to take it with breakfast."}]},{"id":"L17","script":"N: Listen to two colleagues discussing a presentation.\\nM: So, I have finished the slides for the quarterly review.\\nW: Great. Did you include the sales figures for the last three months?\\nM: Yes, I put them in a chart. But I am concerned the chart is too detailed.\\nW: Maybe you could show the highlights and mention that the full data is in the handout.\\nM: That is a good idea. I will simplify the chart and prepare a separate handout.\\nW: Also, remember that we only have twenty minutes, so we should practice timing.","questions":[{"stem":"What is the man worried about?","options":["The sales figures are not ready.","The chart may be too detailed.","The meeting room is not booked.","The handout is too short."],"correct":1,"explanation":"The man says he is concerned the chart is too detailed."},{"stem":"What does the woman suggest?","options":["Remove the chart completely.","Show highlights and mention the handout.","Extend the presentation time.","Ask someone else to present."],"correct":1,"explanation":"She suggests showing highlights and mentioning the full data is in the handout."}]}]},{"id":"listening_part3","title":"Listening Part 3: Short Talks","levelRange":"B2","skill":"listening","moduleType":"listening_set","items":[{"id":"L08","script":"N: Listen to a volunteer coordinator speaking at a museum.\\nCoordinator: Welcome, everyone, and thank you for volunteering at the City Museum this weekend. Please arrive fifteen minutes before your shift starts so you have time to collect your name badge and leave your bags in the staff room. During the event, most of you will be helping visitors find the correct galleries. If a visitor asks you a question you cannot answer, do not guess. Instead, send the visitor to the information desk near the main entrance. Finally, remember that food and drinks are not allowed in the exhibition rooms, so please finish them before you begin your shift.","questions":[{"stem":"What is the main purpose of the talk?","options":["To invite people to a new museum exhibition.","To explain weekend procedures to volunteers.","To describe the history of the museum.","To advertise paid positions."],"correct":1,"explanation":"The coordinator explains procedures volunteers should follow during the weekend event."},{"stem":"What should volunteers do if they do not know an answer?","options":["Ask another visitor.","Look it up on their phones.","Send the visitor to the information desk.","Write the question down for later."],"correct":2,"explanation":"The coordinator says to send the visitor to the information desk near the main entrance."}]},{"id":"L09","script":"N: Listen to a public service announcement.\\nAnnouncer: This is a reminder for residents of North Park. Water service will be temporarily interrupted tonight from ten p.m. until approximately six a.m. while the city replaces an old underground pipe. Residents are advised to store enough water for drinking and basic cleaning before ten p.m. If possible, avoid using washing machines or dishwashers until service is fully restored in the morning. A supply tank with bottled water will be available at the North Park Community Center for elderly residents and others with urgent needs.","questions":[{"stem":"Why will the water service be interrupted?","options":["Because of unusually hot weather.","Because the city is replacing a pipe.","Because the community center is being repaired.","Because residents used too much water."],"correct":1,"explanation":"The announcement says the city is replacing an old underground pipe."},{"stem":"Who is the bottled water especially intended for?","options":["Visitors from outside the area.","Families with school-age children.","Residents with urgent needs, including older people.","City workers on the night shift."],"correct":2,"explanation":"The announcement says 'for elderly residents and others with urgent needs.'"}]},{"id":"L10","script":"N: Listen to part of a podcast.\\nHost: When people feel stuck on a problem, they often assume they should stay at their desks and try harder. In fact, short walks can be surprisingly productive. Movement changes your environment and can interrupt repetitive thinking. One design team I interviewed now holds ten-minute walking meetings whenever they cannot agree on a solution. They say the conversations become calmer, and people tend to suggest more creative ideas. Of course, walking is not a replacement for focused work. You still need time to sit down, review options, and make a decision. But if your thinking starts to go in circles, getting up may be exactly what helps.","questions":[{"stem":"What is the speaker's main point?","options":["Good ideas only come from group discussions.","Walking can help people think more effectively.","Meetings should always take place outdoors.","Designers are more creative than other workers."],"correct":1,"explanation":"The speaker says walking 'can interrupt repetitive thinking' and 'getting up may be exactly what helps.'"},{"stem":"Why does the speaker mention the design team?","options":["To show an example of the strategy in practice.","To criticize the way they make decisions.","To explain why meetings waste time.","To argue against working at a desk."],"correct":0,"explanation":"The design team is given as an example of walking meetings working in practice."}]},{"id":"L18","script":"N: Listen to a university librarian giving a talk.\\nLibrarian: I want to tell you about a new service we are offering this semester. Starting next week, you will be able to book private study rooms online. There are eight rooms available on the second floor, each equipped with a whiteboard and power outlets. You can book a room for up to three hours per day. We ask that you do not leave personal belongings unattended, as the library cannot be responsible for lost items. To book, simply visit the library website and select \\"Study Room Reservation.\\" You will receive a confirmation email with the room number and access code.","questions":[{"stem":"What is the main purpose of the talk?","options":["To announce changes to library hours.","To explain a new study room booking system.","To introduce new library staff.","To promote a book sale."],"correct":1,"explanation":"The librarian is announcing a new service for booking private study rooms."},{"stem":"How can students book a room?","options":["By visiting the library desk.","By calling the library office.","Through the library website.","By emailing a librarian."],"correct":2,"explanation":"The librarian says to visit the library website and select \\"Study Room Reservation.\\""}]},{"id":"L19","script":"N: Listen to a city council member giving an update.\\nCouncilor: Good evening, everyone. I have an update on the Riverside Park renovation project. The playground equipment has been installed and will open to the public next Saturday. Unfortunately, the new walking paths are taking longer than expected because of recent rain. We now expect them to be completed by the end of next month. However, the good news is that the community garden plots are ready for registration. Residents can sign up starting tomorrow at the community center. Each plot costs twenty dollars for the season, and all tools are provided.","questions":[{"stem":"When will the playground open?","options":["Next month.","Next Saturday.","Tomorrow.","At the end of the season."],"correct":1,"explanation":"The councilor says the playground will open to the public next Saturday."},{"stem":"Why have the walking paths been delayed?","options":["Lack of funding.","Recent rainy weather.","Staff shortages.","Problems with suppliers."],"correct":1,"explanation":"The walking paths are delayed because of recent rain."}]},{"id":"L20","script":"N: Listen to a health advice segment on the radio.\\nPresenter: Many of us spend hours sitting at desks, and this can lead to back and neck pain over time. A simple solution is to take what I call \\"movement breaks.\\" Every thirty minutes, stand up, stretch your arms above your head, and walk around your workspace for about a minute. Studies show that people who take regular movement breaks report twenty percent less discomfort at the end of the day. Another tip is to adjust your screen so the top of the monitor is at eye level. This prevents you from leaning forward and straining your neck. Small changes like these can make a big difference to your long-term health.","questions":[{"stem":"How often does the presenter suggest taking movement breaks?","options":["Every hour.","Every thirty minutes.","Every fifteen minutes.","At the start and end of the day."],"correct":1,"explanation":"The presenter suggests taking movement breaks every thirty minutes."},{"stem":"What is one benefit mentioned about regular movement breaks?","options":["Higher productivity at work.","Less discomfort at the end of the day.","Better sleep quality.","Improved concentration."],"correct":1,"explanation":"Studies show people who take breaks report twenty percent less discomfort at the end of the day."}]}]}]`),i={modules:e},t=JSON.parse(`[{"id":"reading_single_mcq","title":"Reading: Single Texts – Multiple Choice (B2)","levelRange":"B2","skill":"reading","moduleType":"reading_set","items":[{"id":"R01","passage":"For years, people have complained that modern products are made to be replaced, not repaired. A broken toaster or lamp is often cheaper to throw away than to fix, especially if spare parts are expensive or difficult to find. In response, many cities have seen the growth of \\"repair cafés,\\" informal events where volunteers help local residents examine damaged objects and, when possible, repair them. At first glance, these gatherings may look like a practical way to save money. In reality, their biggest effect may be social rather than financial.\\n\\nAt a typical repair café, visitors bring household items, clothing, toys, or small electronics. They sit with volunteers who have experience in sewing, wiring, woodworking, or basic mechanical repair. The atmosphere is usually patient rather than hurried. Nobody promises that every object can be saved, and even when something cannot be fixed, the owner often leaves with a better understanding of why it failed. That educational aspect matters. In everyday life, many people interact with devices only as users, not as problem-solvers. A repair café slows that relationship down.\\n\\nThe financial side is more complicated than many supporters admit. Some products are so poorly designed that opening them does more damage. Others require parts that simply are not available. In such cases, a repair café cannot compete with mass retail. Even so, people continue to attend. Organizers say that visitors often return with a second or third object, not because they expect every repair to succeed, but because they value the process itself. They enjoy meeting people with useful skills and seeing that practical knowledge still exists within their community.\\n\\nThere is also an emotional element. When an item has been in a family for years, replacing it can feel like giving up on a small part of personal history. A lamp from a grandparent's house or a jacket repaired several times already may not be valuable in the market, but it can still matter to its owner. Repair cafés make space for that attitude.\\n\\nCritics sometimes argue that repair culture is too small to make a real difference in global waste. Yet it would be a mistake to judge these events only by the number of objects they save. Their larger contribution may be the habit they promote — the habit of pausing before replacing, asking questions before buying, and seeing broken things as problems to understand rather than reasons to consume again.","questions":[{"stem":"What is the main idea of the article?","options":["Repair cafés are mainly successful because they reduce shopping costs.","Repair cafés matter as much for community learning and attitudes as for repair itself.","Repair cafés should receive government funding in every city.","Modern devices are impossible to repair."],"correct":1,"explanation":"The article says the biggest effect is 'social rather than financial' and their contribution is 'the habit they promote.'"},{"stem":"Why does the author mention people returning with a second or third object?","options":["To show that repairs always succeed.","To suggest that volunteers charge low prices.","To support the idea that visitors value the process, not only the result.","To prove that old products are better made."],"correct":2,"explanation":"People return 'not because they expect every repair to succeed, but because they value the process itself.'"},{"stem":"What does \\"slows that relationship down\\" most nearly mean in context?","options":["It makes people buy fewer devices for a short time.","It gives people more time to understand how objects work.","It forces volunteers to work more carefully.","It delays the opening of the event."],"correct":1,"explanation":"In context, a repair café slows the user-device relationship, giving people time to engage with and understand their objects."},{"stem":"Which statement would the author most likely agree with?","options":["Repair cafés are useful even when they do not fix every item.","Repair cafés should focus only on expensive objects.","Emotional attachment makes repair decisions irrational.","Community events should avoid dealing with electronics."],"correct":0,"explanation":"The author says 'it would be a mistake to judge these events only by the number of objects they save.'"},{"stem":"What is the author's attitude toward repair cafés?","options":["Strongly negative.","Cautiously supportive.","Completely impartial.","Mainly disappointed."],"correct":1,"explanation":"The author acknowledges critics but ultimately defends the value of repair cafés."}]},{"id":"R02","passage":"Libraries are often imagined as places defined by silence. For some users, that expectation is exactly the point. They want an environment where conversation is limited and attention can settle. Yet many modern libraries are rethinking what silence should mean. Instead of separating people completely, some are creating spaces that encourage what designers call \\"quiet togetherness\\": being in the presence of others without being required to speak to them.\\n\\nThis idea has grown partly because of changes in work and study habits. More people now divide their day between home, cafés, transport, and temporary study spaces. Working alone at home may be comfortable, but it can also feel isolating. Busy cafés solve the loneliness problem, although they create a different one: noise, movement, and the expectation that customers keep buying something. Libraries occupy a useful middle position. They can offer a public environment where people feel accompanied by others while still being protected from the pressure to socialize or consume.\\n\\nQuiet togetherness is not simply another name for a silent room. In some libraries, it appears through layout decisions rather than rules. Tables are placed in ways that allow people to notice one another without interrupting concentration. Lighting is warm rather than severe. There may be soft indicators that remind users to lower their voices, but staff do not try to remove every sound from the space. The goal is not total silence; it is a shared understanding that everyone is there for focused activity.\\n\\nSupporters say this approach has psychological value. Seeing others reading, writing, or studying can make difficult tasks feel more manageable. People often work longer when they sense a collective purpose around them. In other words, quiet togetherness offers companionship without demand.\\n\\nNot everyone likes the concept. Some traditional users worry that any move away from strict silence weakens the identity of the library. Others say the term is too vague to guide policy. Still, the most successful examples seem to rely on balance rather than replacement. They keep silent rooms for those who want them while also designing other zones where social presence is possible without becoming intrusive.","questions":[{"stem":"The article is mainly about","options":["why cafés are better than libraries for studying.","how libraries are adapting public study space for modern users.","why strict silence should return to libraries.","how urban design affects transportation."],"correct":1,"explanation":"The article describes how libraries are redesigning spaces around 'quiet togetherness' for modern needs."},{"stem":"Why does the author mention cafés?","options":["To argue that libraries should sell drinks.","To show that cafés are more affordable than libraries.","To contrast a social but noisy option with the library model.","To explain where librarians prefer to work."],"correct":2,"explanation":"Cafés are mentioned as a noisy alternative that forces consumption, contrasted with the library's middle-ground position."},{"stem":"What is true of \\"quiet togetherness\\" according to the article?","options":["It requires users to work in groups.","It removes all sound from a space.","It allows social presence without demanding conversation.","It is only useful for school students."],"correct":2,"explanation":"The article says quiet togetherness 'offers companionship without demand.'"},{"stem":"Which concern do critics raise?","options":["The concept may be too unclear to guide decisions.","Libraries are spending too much on furniture.","Silent rooms have become unpopular.","Staff members are unwilling to enforce rules."],"correct":0,"explanation":"Critics say the term is 'too vague to guide policy.'"},{"stem":"What is the author's attitude?","options":["Supportive, while recognizing possible limits.","Opposed to any change in library design.","Uncertain because there is no evidence.","Mostly amused by a passing trend."],"correct":0,"explanation":"The author supports the concept but acknowledges valid concerns — a balanced, cautiously positive view."}]},{"id":"R09","passage":"When people talk about hybrid work, they often focus on productivity. They ask whether staff do more at home, whether meetings become shorter, or whether offices should shrink. A quieter concern receives less attention: friendship. Many workers say that what has changed most is not their task list but the social texture of their day.\\n\\nOffice friendships once grew through repeated, low-pressure contact. People chatted while making coffee, noticed each other's moods, or solved small problems side by side. None of these interactions looked important on their own. Together, however, they built familiarity and trust. In a hybrid system, those moments become less predictable. A person may come in on Tuesday while their closest colleague works from home. After a few months, both people still collaborate, yet they may feel less informed about each other's lives.\\n\\nSome managers respond by creating more formal social events. Team lunches, online quizzes, and scheduled \\"connection sessions\\" are intended to replace what used to happen naturally. These efforts are not useless, but they often feel artificial when overused. Friendship rarely grows because a calendar invitation says it should. It tends to emerge from shared routines and small, repeated exchanges.\\n\\nThat does not mean hybrid work inevitably weakens relationships. Some employees say that seeing colleagues less often makes in-person time feel more valuable, so conversations become more intentional. Others appreciate the reduced pressure to appear sociable every day.\\n\\nThe challenge is not to recreate the old office exactly. It is to notice what kinds of interaction are disappearing and decide which ones matter enough to support. A team may simply need overlap in schedules, enough common time for informal talk, and managers who understand that culture is built partly in the unplanned spaces between tasks.","questions":[{"stem":"What is the article mainly about?","options":["Why productivity matters more than friendship.","How hybrid work can affect workplace friendships.","Why offices should return to full-time schedules.","How managers can organize better quizzes."],"correct":1,"explanation":"The article focuses on the 'quieter concern' of friendship in hybrid work environments."},{"stem":"What does the author suggest about office friendships in the past?","options":["They were usually caused by formal team-building events.","They depended on salary incentives.","They often developed through ordinary repeated contact.","They distracted workers from serious tasks."],"correct":2,"explanation":"Friendships grew through 'repeated, low-pressure contact' like chatting while making coffee."},{"stem":"Why are \\"connection sessions\\" mentioned?","options":["As an example of a forced substitute for natural interaction.","As proof that hybrid work has failed.","As a low-cost way to reduce office space.","As something employees strongly prefer."],"correct":0,"explanation":"They are described as feeling 'artificial when overused' — a poor substitute for natural interaction."},{"stem":"Which statement would the author most likely agree with?","options":["Cultural problems disappear if people meet less often.","Intentional schedule overlap may matter more than social games.","Friendship at work is unprofessional.","Hybrid work affects all employees in exactly the same way."],"correct":1,"explanation":"The author says teams need 'overlap in schedules' and 'common time for informal talk' rather than formal events."},{"stem":"The word \\"texture\\" in paragraph 1 most nearly refers to","options":["the physical design of a building.","the speed of office internet.","the social feel of everyday experience.","a written company policy."],"correct":2,"explanation":"\\"Social texture\\" means the quality and character of day-to-day social experience."}]},{"id":"R11","passage":"In many countries, people are living longer than ever before. This increase in life expectancy is a sign of progress in medicine, nutrition, and public health. However, it also creates challenges for societies, particularly in the areas of healthcare and pensions. When more people live into their eighties and nineties, the demand for medical services rises, and retirement systems must support people for longer periods.\\n\\nSome governments have responded by raising the retirement age, encouraging people to work a few extra years before receiving full pension benefits. Others have introduced incentives for older workers to remain in the workforce part-time. Many companies are also beginning to see the value of experienced employees and are creating flexible roles for those who prefer not to retire completely.\\n\\nAt the community level, some towns are developing programs that connect older adults with younger generations. For example, volunteer tutoring programs allow retirees to share their knowledge with schoolchildren. Such programs benefit both groups: older adults feel valued and active, while younger people receive guidance and support.\\n\\nDespite these efforts, there is still debate about how best to manage the financial costs of an aging population. Some argue that increasing taxes is the only realistic solution, while others believe that encouraging private savings should be the priority. Whatever the approach, it is clear that the aging population will remain a major topic for policymakers in the coming decades.","questions":[{"stem":"What is the article mainly about?","options":["The benefits of modern medicine.","The challenges and responses to longer life expectancy.","How to reduce healthcare costs.","Why retirement age should be lowered."],"correct":1,"explanation":"The article discusses the challenges of longer life expectancy and various responses to them."},{"stem":"What is one way companies are adapting to an aging workforce?","options":["Replacing older workers with younger staff.","Creating flexible roles for experienced employees.","Increasing pension contributions.","Shortening the workday for all employees."],"correct":1,"explanation":"Companies are creating flexible roles for those who prefer not to retire completely."},{"stem":"According to the article, what is a benefit of intergenerational programs?","options":["They reduce healthcare costs.","They help older adults feel valued.","They increase company profits.","They replace formal education."],"correct":1,"explanation":"Intergenerational programs help older adults feel valued and active while younger people receive guidance."},{"stem":"The word \\"incentives\\" in paragraph 2 most nearly means","options":["warnings.","rewards or encouragements.","rules or regulations.","penalties."],"correct":1,"explanation":"Incentives are rewards or encouragements designed to motivate certain behavior."},{"stem":"Which statement would the author most likely agree with?","options":["Solutions to aging population challenges are simple.","The aging population will require ongoing policy attention.","Raising taxes is clearly the best solution.","Older workers should be required to retire at sixty-five."],"correct":1,"explanation":"The author concludes that the aging population will remain a major topic for policymakers."}]}]},{"id":"reading_multi_mcq","title":"Reading: Multiple Texts – Multiple Choice (B2)","levelRange":"B2","skill":"reading","moduleType":"reading_set","items":[{"id":"R03","passage":"TEXT A — Rail company brochure\\nNight travel gives you a full day at your destination instead of a long journey in daylight. On our new Moonline route, passengers can choose standard seats, shared sleeper cabins, or private cabins with breakfast included. Free Wi-Fi is available in all cars, and bicycles may be transported for an additional fee if booked in advance.\\n\\nTEXT B — Travel blog\\nI took the Moonline last month and was surprised by how rested I felt on arrival. The cabin was small, but much quieter than I expected. The only real inconvenience was breakfast, which was delivered too early for me. I would definitely choose the train again over a budget flight, especially because I didn't lose half a day getting to and from airports.\\n\\nTEXT C — News report\\nRegional officials say the return of overnight rail could reduce short domestic flights if prices remain competitive. However, transport analysts warn that the service will only attract regular users if reliability improves. In earlier trials, delays on morning arrival made the option less appealing to business travelers. Operators insist the new timetable includes greater recovery time to avoid that problem.","questions":[{"stem":"What is the purpose of Text A?","options":["To criticize airline travel.","To describe and promote a service.","To report on transport policy.","To compare train companies."],"correct":1,"explanation":"Text A is a rail company brochure — it describes and promotes the Moonline service."},{"stem":"What complaint does the writer of Text B mention?","options":["The train was noisy.","Breakfast came too early.","Wi-Fi was unreliable.","The cabin was expensive."],"correct":1,"explanation":"The writer says 'The only real inconvenience was breakfast, which was delivered too early for me.'"},{"stem":"According to Text C, what condition is important for long-term success?","options":["Free bicycle transport.","Fewer sleeper cabins.","Competitive prices and reliable arrival times.","Later evening departures."],"correct":2,"explanation":"Analysts say the service needs competitive prices and improved reliability."},{"stem":"Which text is most positive in tone?","options":["Text A.","Text B.","Text C.","All are equally neutral."],"correct":1,"explanation":"Text B expresses personal enthusiasm: 'I would definitely choose the train again.'"},{"stem":"Which idea appears in more than one text?","options":["Airport security is stressful.","Night trains appeal partly because they save daytime hours.","Private cabins should be removed.","Breakfast quality determines user satisfaction."],"correct":1,"explanation":"Text A says you get 'a full day at your destination'; Text B says the blogger 'didn't lose half a day getting to and from airports.'"}]},{"id":"R04","passage":"TEXT A — Festival volunteer notice\\nVolunteers are needed for the Riverside Food Festival next month. Tasks include greeting visitors, checking tickets, and helping stall owners move light equipment before opening. Morning and evening shifts are available. Volunteers receive a festival T-shirt, free entry on one day, and a reference letter on request.\\n\\nTEXT B — Email from a volunteer coordinator\\nThanks for your interest in helping at the festival. Since you said you're comfortable speaking to the public, the greeting team might suit you best. Please note that the morning shift starts at 7:30 a.m., earlier than many first-time volunteers expect. If that is a problem, let me know and I can assign you to an afternoon role instead.\\n\\nTEXT C — Volunteer review\\nI volunteered last year and ended up enjoying it more than I expected. The work was tiring at times, especially before the gates opened, but the team leaders explained things clearly and everyone was friendly. What I appreciated most was being trusted to solve small problems instead of waiting for instructions all the time.","questions":[{"stem":"Which text is mainly designed to recruit people?","options":["Text A.","Text B.","Text C.","Texts A and C."],"correct":0,"explanation":"Text A is a volunteer notice asking for people to sign up — it is designed to recruit."},{"stem":"What does Text B suggest about the candidate?","options":["They asked for office work only.","They may be well suited to greeting visitors.","They volunteered the previous year.","They are not available in the afternoon."],"correct":1,"explanation":"The coordinator says 'the greeting team might suit you best' based on comfort with speaking to the public."},{"stem":"What is the reviewer's overall opinion in Text C?","options":["Mostly negative.","Positive despite some tiring moments.","Unclear because of missing details.","Frustrated with management."],"correct":1,"explanation":"The reviewer says they 'ended up enjoying it more than I expected' — positive, despite some tiring moments."},{"stem":"Which text mentions a possible scheduling issue?","options":["Text A only.","Text B only.","Text C only.","Texts A and B."],"correct":3,"explanation":"Text A lists morning and evening shifts; Text B flags the 7:30 a.m. start as potentially early for first-timers."},{"stem":"Which statement is supported by the set as a whole?","options":["Festival volunteering is unpaid but may bring other benefits.","New volunteers cannot speak to the public.","All roles begin before 8:00 a.m.","Team leaders expect volunteers to work independently immediately."],"correct":0,"explanation":"Text A lists a T-shirt, free entry, and reference letter — non-pay benefits."}]},{"id":"R10","passage":"TEXT A — Community sports flyer\\nTry a new activity this summer at Eastside Sports Center. Adults can choose beginner tennis, evening running groups, and low-impact fitness classes. Reduced prices are available for residents over sixty and for students with valid identification. Registration opens online on Monday.\\n\\nTEXT B — Interview excerpt\\nCoach Marina Lopez says the biggest challenge for adult beginners is not physical ability but confidence. \\"People think everyone else already knows what they're doing,\\" she says. \\"Once they realize the class is designed for first-timers, they usually relax.\\"\\n\\nTEXT C — Local news item\\nCity health officials welcomed the expansion of low-cost sports programs, saying that access matters as much as motivation. Previous surveys showed strong interest in exercise classes, but cost and travel distance often prevented residents from joining.","questions":[{"stem":"Which text mainly provides practical sign-up information?","options":["Text A.","Text B.","Text C.","Texts B and C."],"correct":0,"explanation":"Text A is a flyer with activities, prices, and registration details."},{"stem":"According to Text B, what stops many adult beginners?","options":["Lack of free time.","Fear of not being good enough.","High equipment costs.","Limited bus service."],"correct":1,"explanation":"Coach Lopez says the challenge is 'confidence' — people worry that everyone else knows what they're doing."},{"stem":"What point is made in Text C?","options":["Coaches should design harder classes.","Motivation is the only real problem.","Access barriers can prevent participation.","Tennis is more popular than running."],"correct":2,"explanation":"Text C says cost and travel distance 'often prevented residents from joining' — access barriers."},{"stem":"Which text would be most useful to someone deciding whether classes suit a novice?","options":["Text A.","Text B.","Text C.","None of them."],"correct":1,"explanation":"Text B specifically addresses beginners and says classes are designed for first-timers."},{"stem":"Which idea connects Texts A and C most clearly?","options":["Discounts and affordability can influence participation.","Running groups should be moved online.","Surveys are more useful than coaching.","Programs should only target older residents."],"correct":0,"explanation":"Text A mentions reduced prices; Text C notes that cost 'often prevented residents from joining.'"}]},{"id":"R12","passage":"TEXT A — Community notice\\nGreenwood Neighborhood Association is organizing a Clean-Up Day on Saturday, April 22, from 9 a.m. to 1 p.m. Volunteers are needed to pick up litter, plant flowers in the public garden, and paint benches in the park. Gloves, paint, and garbage bags will be provided. Volunteers should bring their own water bottles. A free lunch will be served at noon.\\n\\nTEXT B — Email newsletter\\nLast year's neighborhood clean-up was a great success, with over sixty volunteers participating. Organizers are hoping for an even bigger turnout this spring. New this year: a children's planting corner where young residents can learn about gardening. If you plan to join, please register online so the team can order enough supplies. The weather forecast looks favorable, so we expect a productive day.\\n\\nTEXT C — Online comment from a resident\\nI attended the clean-up last year and really enjoyed it. The atmosphere was friendly, and it felt good to see the park looking better afterward. The only downside was that we ran out of paint for the benches by late morning. I hope this year they bring more supplies. Overall, though, I would definitely recommend joining.","questions":[{"stem":"What is the purpose of Text A?","options":["To report on a past event.","To announce and invite people to an event.","To criticize the neighborhood association.","To compare different volunteer activities."],"correct":1,"explanation":"Text A is a notice announcing the Clean-Up Day and calling for volunteers."},{"stem":"What does Text B mention that is new this year?","options":["A free lunch for volunteers.","A children's planting corner.","Longer working hours.","A different meeting location."],"correct":1,"explanation":"Text B says new this year is a children's planting corner."},{"stem":"What concern does the writer of Text C raise?","options":["The event started too late.","There was not enough paint.","The weather was bad.","Not enough people attended."],"correct":1,"explanation":"Text C says they ran out of paint for the benches."},{"stem":"Which text is most likely to persuade someone to join for the first time?","options":["Text A.","Text B.","Text C.","All equally."],"correct":2,"explanation":"Text C gives a first-person positive experience, which is persuasive for newcomers."},{"stem":"Which detail appears in Text A but NOT in Text B or C?","options":["Volunteers should bring water bottles.","There will be a children's activity.","Registration is online.","Lunch will be served."],"correct":0,"explanation":"Only Text A mentions bringing water bottles."}]}]},{"id":"reading_tfng","title":"Reading: True / False / Not Given (B2)","levelRange":"B2","skill":"reading","moduleType":"tfng_set","items":[{"id":"R05","passage":"In many offices, long emails are treated as signs of seriousness. A detailed message can look thoughtful and complete, especially when a topic is complicated. Yet communication researchers have increasingly questioned whether length improves workplace understanding. In many cases, the opposite seems to be true: when readers are busy, they often respond more effectively to shorter emails with a clear structure and one obvious purpose.\\n\\nThis does not mean all emails should be extremely brief. Some decisions require explanation, and some messages need context. The problem appears when writers include too many small points in one message. Readers then have to decide what matters most. If they miss the real request, both sides lose time.\\n\\nA more effective strategy is often to divide communication by function. One email can ask for a decision. Another can provide background information. Shorter emails may even sound more polite. A reader who receives a focused message may feel that the writer has respected their time.\\n\\nHowever, this trend has limits. In highly sensitive situations, very short emails can appear cold or abrupt. Tone matters, and so does the relationship between the people involved. Good email practice is not about making every message short. It is about matching length and structure to purpose.","statements":[{"text":"The text says long emails are always ineffective.","correct":1,"explanation":"False. The article says 'This does not mean all emails should be extremely brief.'"},{"text":"Researchers have questioned the value of length in workplace emails.","correct":0,"explanation":"True. The article states that 'communication researchers have increasingly questioned whether length improves workplace understanding.'"},{"text":"The writer thinks one email should contain only one clear purpose whenever possible.","correct":0,"explanation":"True. The article recommends dividing communication by function so each email has one obvious purpose."},{"text":"The text says short emails are always more polite.","correct":1,"explanation":"False. Short emails 'may even sound more polite' but can also appear 'cold or abrupt' in sensitive situations."},{"text":"Very short emails can sometimes sound unfriendly.","correct":0,"explanation":"True. The article says 'very short emails can appear cold or abrupt' in sensitive situations."},{"text":"The article states that customers prefer bullet points to short paragraphs.","correct":2,"explanation":"Not Given. The article mentions bullet points but does not state any customer preference for one format over another."}]},{"id":"R13","passage":"Urban farming is becoming increasingly popular in cities around the world. Rooftop gardens, community plots, and vertical farms are appearing in places where traditional agriculture would seem impossible. Supporters argue that growing food in cities reduces transportation costs, provides fresh produce, and creates green spaces that improve air quality.\\n\\nHowever, urban farming is not without its difficulties. Space is limited, soil quality can be poor, and city regulations sometimes restrict what residents can grow. Despite these challenges, many cities have begun supporting urban agriculture through grants and policy changes. Some have even converted empty lots into community gardens that residents can use for free.\\n\\nCritics point out that urban farming cannot replace large-scale agriculture. The amount of food grown in cities is small compared to what rural farms produce. But advocates argue that this misses the point. Urban farming is not meant to replace rural agriculture. Instead, it is meant to complement it by improving food access in neighborhoods that lack grocery stores.\\n\\nIn the end, urban farming may be most valuable for its social benefits. Community gardens bring neighbors together, teach valuable skills, and encourage healthier eating habits. These effects, though hard to measure, may be just as important as the food itself.","statements":[{"text":"Urban farming is only possible in warm climates.","correct":2,"explanation":"Not Given. The article does not discuss climate requirements for urban farming."},{"text":"Some cities provide financial support for urban agriculture.","correct":0,"explanation":"True. The article says cities support urban agriculture through grants and policy changes."},{"text":"The article says urban farming can replace traditional rural agriculture.","correct":1,"explanation":"False. The article says urban farming is not meant to replace rural agriculture."},{"text":"Community gardens can help build social connections.","correct":0,"explanation":"True. The article says community gardens bring neighbors together."},{"text":"Urban farming produces more food than rural farms.","correct":1,"explanation":"False. Critics point out the amount grown in cities is small compared to rural farms."}]},{"id":"R14","passage":"The way we communicate has changed dramatically over the past twenty years. Text messages, instant messaging, and social media have largely replaced phone calls and letters for everyday communication. While this has made communication faster and more convenient, some researchers worry that important conversational skills are being lost.\\n\\nOne concern is that people are becoming less comfortable with real-time conversation. When messaging, you have time to think before responding. In face-to-face or phone conversations, you need to listen, process, and respond immediately. Young people who have grown up with texting may find this more challenging.\\n\\nAnother issue is that written messages lack tone of voice, facial expressions, and body language. This can lead to misunderstandings. A simple message like \\"Fine\\" can mean agreement, annoyance, or resignation depending on how it is said. Online, the reader has to guess.\\n\\nHowever, defenders of digital communication point out that it allows for more thoughtful responses. People can edit their messages, research their answers, and express ideas more precisely. They argue that different situations call for different communication methods, and that being skilled at both written and spoken communication is the real goal.","statements":[{"text":"Phone calls have become more popular than texting.","correct":1,"explanation":"False. The article says texting and messaging have largely replaced phone calls."},{"text":"Real-time conversation requires immediate responses.","correct":0,"explanation":"True. The article says you need to listen, process, and respond immediately."},{"text":"Online messages always carry the intended tone correctly.","correct":1,"explanation":"False. The article says written messages lack tone of voice and can lead to misunderstandings."},{"text":"The article mentions that digital communication allows people to edit their responses.","correct":0,"explanation":"True. Defenders of digital communication say people can edit their messages."},{"text":"The author believes everyone should stop using text messages.","correct":2,"explanation":"Not Given. The author presents both sides but does not state a personal preference."}]}]}]`),n={modules:t},a=[{id:"writing_q1",title:"Writing – Q1: Opinion & Argument (B2)",levelRange:"B2",skill:"writing",moduleType:"exercise_list",exercises:[{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Some people believe schools should start later in the morning. Do you agree or disagree? Give reasons and examples. (180–250 words)",rubric:"State your opinion clearly. Support with reasons and examples. Use formal register.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Should cities offer cheaper public transportation to students and young workers? Give your opinion and support it with examples. (180–250 words)",rubric:"Develop a clear argument with supporting points. Use formal vocabulary and logical connectors.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Do companies have a responsibility to limit work messages outside normal working hours? Explain your opinion. (180–250 words)",rubric:"Present your position with reasons, possible counter-arguments, and a conclusion.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Some universities want to make community service a required part of graduation. Is this a good idea? Why or why not? (180–250 words)",rubric:"Discuss advantages and disadvantages. Provide a clear personal stance with supporting evidence.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Should online stores be required to use simpler, reusable, or recyclable packaging whenever possible? Give your opinion. (180–250 words)",rubric:"Support your opinion with reasons. Acknowledge counterarguments where appropriate.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Is taking a gap year before university a good idea for most students? Explain your view. (180–250 words)",rubric:"Balance advantages and disadvantages. Write a well-supported conclusion.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Should phones be completely banned in classrooms? Give reasons for your answer. (180–250 words)",rubric:"Present both sides of the argument. State your view clearly and defend it.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Do you think a four-day working week is a good idea for most businesses? Explain your answer. (180–250 words)",rubric:"Discuss with specific reasoning. Use formal vocabulary and varied grammar.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Some people believe that online shopping will completely replace physical stores in the future. Do you agree or disagree? Give reasons and examples. (180–250 words)",rubric:"State your position clearly, provide reasons, and discuss counterarguments.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Should all students be required to learn a second language in school? Discuss the advantages and give your opinion. (180–250 words)",rubric:"Discuss both sides, provide examples, and state your conclusion clearly.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Should companies be required to offer paid volunteer days to their employees? Give your opinion and support it. (180–250 words)",rubric:"Develop a clear argument with reasons and consider opposing views.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Is it better to specialize in one career or to try different types of jobs during your life? Explain your view. (180–250 words)",rubric:"Compare both approaches, provide examples, and state your preference with reasons.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Should governments invest more in public transportation or in roads for private cars? Explain your position. (180–250 words)",rubric:"Compare the two options with reasoning and examples. State your preference clearly.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Do you think learning practical skills like cooking and budgeting should be taught in schools? Why or why not? (180–250 words)",rubric:"Present your opinion with clear reasoning. Address possible counterarguments.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Some professionals, such as doctors and teachers, are paid less than entertainers and athletes. Is this fair? Discuss. (180–250 words)",rubric:"Compare the value of different professions. Provide reasons and examples.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q1",metTask:"Opinion essay",prompt:"Should museums and historical sites offer free admission to all visitors? Give reasons for your answer. (180–250 words)",rubric:"Discuss advantages and disadvantages. Give a clear personal opinion with support.",targetWords:200}]},{id:"writing_q2",title:"Writing – Q2: Discussion & Balanced Argument (B2)",levelRange:"B2",skill:"writing",moduleType:"exercise_list",exercises:[{type:"short",level:"B2",skill:"writing",question:"q2",metTask:"Discussion essay",prompt:"Many companies now allow some employees to work from home several days a week. What are the advantages and disadvantages of this change? Give reasons and examples to support your answer. (180–250 words)",rubric:"Task Completion, Grammar, Vocabulary, Cohesion & Organisation. Use formal register.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q2",metTask:"Discussion essay",prompt:"Tourism can help small towns, but it can also create problems. Discuss the advantages and disadvantages. (180–250 words)",rubric:"Develop both sides equally. Provide a balanced conclusion with your overall view.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q2",metTask:"Discussion essay",prompt:"Some people say that social media brings people closer together, while others say it pushes them apart. What is your opinion? (180–250 words)",rubric:"Discuss both arguments, support with specific examples, and give a balanced conclusion.",targetWords:200},{type:"short",level:"B2",skill:"writing",question:"q2",metTask:"Discussion essay",prompt:"Many cities are creating more car-free zones in their downtown areas. What are the benefits of this approach, and are there any downsides? (180–250 words)",rubric:"Balance pros and cons, provide specific examples, and give a reasoned conclusion.",targetWords:200}]}],r={modules:a},o=[{id:"speaking_q1",title:"Speaking – Q1: Describe a Picture (B2)",levelRange:"B2",skill:"speaking",moduleType:"exercise_list",exercises:[{type:"speak",level:"B2",skill:"speaking",question:"q1",metTask:"Picture description",prompt:"Look at the picture and describe what you see. [Picture: two people building a bookcase in a small apartment; boxes on the floor; one person reads the instructions]",imageUrl:"https://www.supabase.co/storage/v1/object/public/exercise-images/speaking_q1_image.png",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q1",metTask:"Picture description",prompt:"Look at the picture and describe what you see. [Picture: people waiting for a bus in heavy rain; one person sharing an umbrella; busy street in background]",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q1",metTask:"Picture description",prompt:"Look at the picture and describe what you see. [Picture: a busy hospital waiting room; people sitting; a nurse speaking to a patient at the reception desk]",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q1",metTask:"Picture description",prompt:"Look at the picture and describe what you see. [Picture: a family eating dinner together around a table; different generations present; food in the center of the table]",targetSeconds:60}]},{id:"speaking_q2",title:"Speaking – Q2: Personal Narrative (B2)",levelRange:"B2",skill:"speaking",moduleType:"exercise_list",exercises:[{type:"speak",level:"B2",skill:"speaking",question:"q2",metTask:"Personal narrative",prompt:"Tell me about a time when you learned a practical skill from someone else.",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q2",metTask:"Personal narrative",prompt:"Tell me about a time when you were late and had to solve the problem quickly.",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q2",metTask:"Personal narrative",prompt:"Tell me about a time when you volunteered to help someone or something. What did you do and how did it make you feel?",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q2",metTask:"Personal narrative",prompt:"Tell me about a skill you had to learn through practice and patience. How did you approach learning it?",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q2",metTask:"Personal narrative",prompt:"Tell me about a time when you had to make a difficult decision. What was the situation and how did you decide what to do?",targetSeconds:60}]},{id:"speaking_q3",title:"Speaking – Q3: Opinion & Preference (B2)",levelRange:"B2",skill:"speaking",moduleType:"exercise_list",exercises:[{type:"speak",level:"B2",skill:"speaking",question:"q3",metTask:"Opinion",prompt:"Some people prefer buying things new. Other people prefer buying second-hand items. What do you prefer? Give reasons.",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q3",metTask:"Opinion",prompt:"Is it better to study or work in silence, or with background music? Give your opinion and reasons.",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q3",metTask:"Opinion",prompt:"Some people prefer to plan their holidays carefully. Others prefer to be spontaneous. Which type are you? Give reasons.",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q3",metTask:"Opinion",prompt:"Do you think it is better to live in a big city or a small town? Give your opinion with reasons.",targetSeconds:60},{type:"speak",level:"B2",skill:"speaking",question:"q3",metTask:"Opinion",prompt:"Is it better to spend money on experiences, like travel and concerts, or on material things? Give your opinion.",targetSeconds:60}]},{id:"speaking_q4",title:"Speaking – Q4: Advantages & Disadvantages (B2)",levelRange:"B2",skill:"speaking",moduleType:"exercise_list",exercises:[{type:"speak",level:"B2",skill:"speaking",question:"q4",metTask:"Advantages & disadvantages",prompt:"Your college is considering moving one day of classes each week online. What are the advantages and disadvantages of this idea?",targetSeconds:90},{type:"speak",level:"B2",skill:"speaking",question:"q4",metTask:"Advantages & disadvantages",prompt:"A company wants employees to use shared desks instead of having fixed desks. What are the advantages and disadvantages?",targetSeconds:90}]},{id:"speaking_q5",title:"Speaking – Q5: Role-Play & Persuasion (B2)",levelRange:"B2",skill:"speaking",moduleType:"exercise_list",exercises:[{type:"speak",level:"B2",skill:"speaking",question:"q5",metTask:"Role-play",prompt:"The school principal is considering extending library opening hours in the evening. Talk to the principal. Explain what you think and try to convince them to agree with you.",targetSeconds:90},{type:"speak",level:"B2",skill:"speaking",question:"q5",metTask:"Role-play",prompt:"A city official is deciding whether to add more bicycle parking near the train station. Talk to the official and explain why you agree or disagree.",targetSeconds:90},{type:"speak",level:"B2",skill:"speaking",question:"q5",metTask:"Role-play",prompt:"Your workplace is considering installing a gym and relaxation room for employees. Talk to your manager and explain why you think this is a good idea.",targetSeconds:90},{type:"speak",level:"B2",skill:"speaking",question:"q5",metTask:"Role-play",prompt:"A local library is planning to reduce its physical book collection to make space for a digital media lab. Talk to the librarian and share your opinion.",targetSeconds:90}]}],l={modules:o},s=[{id:"grammar_sentence_completion",title:"Grammar: Sentence Completion (B2)",levelRange:"B2",skill:"grammar",moduleType:"mcq_set",items:[{stem:"By the time we arrived, the meeting ______.",options:["already finished","has already finished","had already finished","was already finishing"],correct:2,explanation:"Past perfect is used for an action completed before another past event."},{stem:"She apologized ______ replying so late.",options:["for","of","about","to"],correct:0,explanation:"'Apologize for + -ing' is the correct pattern."},{stem:"If I ______ more free time, I'd join the evening course.",options:["have","had","would have","will have"],correct:1,explanation:"Second conditional uses 'If + past simple, would + infinitive.'"},{stem:"The manager suggested ______ the decision until Monday.",options:["to delay","delaying","delay","delayed"],correct:1,explanation:"'Suggest + -ing' (gerund) is the correct pattern."},{stem:"This is the shop ______ I bought my laptop.",options:["which","where","who","whose"],correct:1,explanation:"'Where' is the relative adverb used for places."},{stem:"The company expects its employees ______ on time.",options:["to arrive","arrive","arriving","arrived"],correct:0,explanation:"'Expect someone to do something' is the correct structure."},{stem:"______ the rain, the outdoor concert went ahead as planned.",options:["Because","Despite","Although","However"],correct:1,explanation:"'Despite + noun' is used to show contrast."},{stem:"I'd rather you ______ me before making the decision.",options:["tell","told","telling","have told"],correct:1,explanation:"'I'd rather you + past simple' is used for preferences about someone else's actions."}]},{id:"grammar_open_cloze",title:"Grammar: Open Cloze (B2)",levelRange:"B2",skill:"grammar",moduleType:"exercise_list",exercises:[{type:"blank",level:"B2",skill:"grammar",template:"Last year our neighborhood started a small book exchange. At first, people were unsure ___ it would work, but within a few weeks the shelves were full. The success came partly ___ the rules were simple: take a book, leave a book. Since then, many residents ___ discovered authors they had never read before. The project is small, ___ it has changed the way people talk to one another. It has even given neighbors a reason to stop ___ chat for a few minutes.",blanks:["whether","because","have","but","and"]},{type:"blank",level:"B2",skill:"grammar",template:"Online courses have become extremely popular in recent years. Many students prefer them ___ they can study at their own pace. However, not everyone is suited ___ this type of learning. You need to be highly self-motivated, ___ you will quickly fall behind. Some students say they miss ___ opportunity to ask questions immediately. Others feel ___ the lack of social interaction makes learning less enjoyable.",blanks:["because","to","or","the","that"]}]},{id:"grammar_error_correction",title:"Grammar: Error Correction (B2)",levelRange:"B2",skill:"grammar",moduleType:"exercise_list",exercises:[{type:"fix",level:"B2",skill:"grammar",errorText:"He asked me where was the station.",correctedText:"He asked me where the station was.",hint:"Reported questions use statement word order, not question word order."},{type:"fix",level:"B2",skill:"grammar",errorText:"I look forward to hear from you.",correctedText:"I look forward to hearing from you.",hint:"'Look forward to' is followed by a gerund (-ing form), not an infinitive."},{type:"fix",level:"B2",skill:"grammar",errorText:"She has less friends than her brother.",correctedText:"She has fewer friends than her brother.",hint:"Use 'fewer' with countable nouns and 'less' with uncountable nouns."},{type:"fix",level:"B2",skill:"grammar",errorText:"If I would know the answer, I'd tell you.",correctedText:"If I knew the answer, I'd tell you.",hint:"In second conditional, the 'if' clause uses past simple, not 'would'."},{type:"fix",level:"B2",skill:"grammar",errorText:"The report was wrote yesterday.",correctedText:"The report was written yesterday.",hint:"Passive voice requires 'was/were' + past participle ('written', not 'wrote')."},{type:"fix",level:"B2",skill:"grammar",errorText:"She is enough old to drive a car.",correctedText:"She is old enough to drive a car.",hint:'Adjective comes before "enough", not after it.'},{type:"fix",level:"B2",skill:"grammar",errorText:"I used to could speak Spanish fluently.",correctedText:"I used to be able to speak Spanish fluently.",hint:'"Used to" is followed by the infinitive, not "could".'}]},{id:"grammar_word_formation",title:"Grammar: Word Formation (B2)",levelRange:"B2",skill:"grammar",moduleType:"exercise_list",exercises:[{type:"blank",level:"B2",skill:"grammar",template:"The new system was designed to improve ___ between departments. (COMMUNICATE)",blanks:["communication"]},{type:"blank",level:"B2",skill:"grammar",template:"Her explanation was clear and very ___. (CONVINCE)",blanks:["convincing"]},{type:"blank",level:"B2",skill:"grammar",template:"We were surprised by the ___ of the final results. (ACCURATE)",blanks:["accuracy"]},{type:"blank",level:"B2",skill:"grammar",template:"Good public transport increases the ___ of jobs and services. (ACCESS)",blanks:["accessibility"]},{type:"blank",level:"B2",skill:"grammar",template:"The course encourages students to think more ___. (CRITIC)",blanks:["critically"]},{type:"blank",level:"B2",skill:"grammar",template:"The documentary provided a detailed ___ of the problem. (EXPLAIN)",blanks:["explanation"]}]},{id:"grammar_mixed_tenses",title:"Grammar: Mixed Tenses (B2)",levelRange:"B2",skill:"grammar",moduleType:"exercise_list",exercises:[{type:"blank",level:"B2",skill:"grammar",template:"While I ___ (walk) to work, I saw an old friend.",blanks:["was walking"]},{type:"blank",level:"B2",skill:"grammar",template:"They ___ (live) here since 2022.",blanks:["have lived|have been living"]},{type:"blank",level:"B2",skill:"grammar",template:"By next June, she ___ (finish) her degree.",blanks:["will have finished"]},{type:"blank",level:"B2",skill:"grammar",template:"I didn't answer because I ___ (drive).",blanks:["was driving"]},{type:"blank",level:"B2",skill:"grammar",template:"He said he ___ (not see) the message yet.",blanks:["had not seen|hadn't seen"]},{type:"blank",level:"B2",skill:"grammar",template:"I ___ (wait) for the bus for over an hour when it finally arrived.",blanks:["had been waiting"]}]},{id:"grammar_conditionals",title:"Grammar: Conditionals & Wishes (B2)",levelRange:"B2",skill:"grammar",moduleType:"exercise_list",exercises:[{type:"blank",level:"B2",skill:"grammar",template:"If people ___ (cycle) more often, the city would be less polluted.",blanks:["cycled"]},{type:"blank",level:"B2",skill:"grammar",template:"I wish I ___ (have) enough time to join the course last year.",blanks:["had had"]},{type:"blank",level:"B2",skill:"grammar",template:"If she had left earlier, she ___ (catch) the train.",blanks:["would have caught"]},{type:"blank",level:"B2",skill:"grammar",template:"If I were you, I ___ (speak) to the manager directly.",blanks:["would speak"]},{type:"blank",level:"B2",skill:"grammar",template:"He wishes he ___ (not spend) so much money on things he didn't need.",blanks:["hadn't spent|had not spent"]},{type:"blank",level:"B2",skill:"grammar",template:"Unless the weather ___ (improve), the match will be cancelled.",blanks:["improves"]}]},{id:"grammar_modals",title:"Grammar: Modals (B2)",levelRange:"B2",skill:"grammar",moduleType:"exercise_list",exercises:[{type:"blank",level:"B2",skill:"grammar",template:"You ___ bring your ID; they won't let you in without it.",blanks:["must"]},{type:"blank",level:"B2",skill:"grammar",template:"She looks exhausted. She ___ have slept very little.",blanks:["must"]},{type:"blank",level:"B2",skill:"grammar",template:"They ___ have taken the earlier train; they're already here.",blanks:["must"]},{type:"blank",level:"B2",skill:"grammar",template:"You ___ smoke here; it's against the rules.",blanks:["mustn't|must not"]},{type:"blank",level:"B2",skill:"grammar",template:"We ___ meet tomorrow if you're free, but it isn't final yet.",blanks:["might"]},{type:"blank",level:"B2",skill:"grammar",template:"You ___ (not need) bring anything to the party — everything is provided.",blanks:["don't need to|do not need to"]}]}],h={modules:s};export{h as g,i as l,n as r,l as s,r as w};
